cd /app && node -e "
import { DEFAULT_CONFIG, validateConfig, validateUrl, findConfig, readConfig, writeConfig } from './src/config.js';

// 1. DEFAULT_CONFIG
console.log('DEFAULT_CONFIG:', JSON.stringify(DEFAULT_CONFIG));

// 2. validateUrl
console.log('validateUrl ok:', validateUrl('https://example.com'));
console.log('validateUrl bad:', validateUrl('ftp://bad'));
console.log('validateUrl empty:', validateUrl(''));

// 3. validateConfig — valid
const good = { name: 'Test', links: [{ label: 'Site', url: 'https://x.com' }] };
console.log('valid config:', validateConfig(good));

// 4. validateConfig — multiple errors
const bad = { links: [{ url: 'bad' }, { label: 'ok' }] };
console.log('invalid config:', validateConfig(bad));

// 5. writeConfig + readConfig round-trip
import { mkdtempSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
const dir = mkdtempSync(join(tmpdir(), 'links-test-'));
const file = join(dir, 'links.yaml');
writeConfig(file, { name: 'Round Trip', theme: 'minimal-dark', links: [{ label: 'A', url: 'https://a.com' }] });
const parsed = readConfig(file);
console.log('round-trip:', JSON.stringify(parsed));
rmSync(dir, { recursive: true });

// 6. findConfig — not found
try { findConfig('/tmp/empty-dir-that-does-not-exist-abc123'); } catch(e) { console.log('findConfig err:', e.message); }

console.log('All checks passed.');
"

